1	<script lang="ts">
2		import type { Snippet } from 'svelte';
3	
4		interface TooltipProps {
5			content?: string;
6			tooltip?: Snippet;
7			children?: Snippet;
8			disabled?: boolean;
9			disabledTrigger?: boolean;
10			delayDuration?: number;
11			side?: 'top' | 'right' | 'bottom' | 'left';
12			align?: 'start' | 'center' | 'end';
13		}
14	
15		let {
16			content,
17			tooltip,
18			children,
19			disabled = false,
20			disabledTrigger = false,
21			delayDuration = 250,
22			side = 'top',
23			align = 'center'
24		}: TooltipProps = $props();
25	
26		let open = $state(false);
27		let timeout: number | null = null;
28		const tooltipId = `tooltip-${Math.random().toString(36).slice(2)}`;
29	
30		function show() {
31			if (disabled) return;
32			if (timeout) window.clearTimeout(timeout);
33			timeout = window.setTimeout(() => {
34				open = true;
35				timeout = null;
36			}, delayDuration);
37		}
38	
39		function hide() {
40			if (timeout) {
41				window.clearTimeout(timeout);
42				timeout = null;
43			}
44			open = false;
45		}
46	
47		function sideClass(): string {
48			switch (side) {
49				case 'right':
50					return 'top-1/2 left-full ml-2 -translate-y-1/2';
51				case 'bottom':
52					return 'top-full mt-2';
53				case 'left':
54					return 'top-1/2 right-full mr-2 -translate-y-1/2';
55				default:
56					return 'bottom-full mb-2';
57			}
58		}
59	
60		function alignClass(): string {
61			if (side === 'left' || side === 'right') {
62				return 'translate-x-0';
63			}
64			switch (align) {
65				case 'start':
66					return 'left-0';
67				case 'end':
68					return 'right-0';
69				default:
70					return 'left-1/2 -translate-x-1/2';
71			}
72		}
73	</script>
74	
75	<span
76		role="presentation"
77		class="relative inline-flex max-w-full align-middle"
78		data-disabled-trigger={disabledTrigger ? '' : undefined}
79		aria-describedby={open ? tooltipId : undefined}
80		onpointerenter={show}
81		onpointerleave={hide}
82		onfocusin={show}
83		onfocusout={hide}
84	>
85		{@render children?.()}
86		{#if open}
